1. using System.Text.RegularExpressions;
2. using Contoso.Text;
3. 
4. namespace Contoso.Text.Tests;
5. 
6. [TestClass]
7. public class StringFormatterTests
8. {
9.     private readonly StringFormatter _formatter = new();
10. 
11.     // ── FormatPhoneNumber ──────────────────────────────────────────
12. 
13.     [TestMethod]
14.     public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
15.     {
16.         var result = _formatter.FormatPhoneNumber("1234567890");
17. 
18.         Assert.AreEqual("(123) 456-7890", result);
19.     }
20. 
21.     [TestMethod]
22.     public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
23.     {
24.         var result = _formatter.FormatPhoneNumber("8005551234");
25. 
26.         StringAssert.StartsWith(result, "(800)");
27.     }
28. 
29.     [TestMethod]
30.     public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
31.     {
32.         var result = _formatter.FormatPhoneNumber("8005551234");
33. 
34.         StringAssert.EndsWith(result, "1234");
35.     }
36. 
37.     [TestMethod]
38.     public void FormatPhoneNumber_Result_ContainsDashSeparator()
39.     {
40.         var result = _formatter.FormatPhoneNumber("8005551234");
41. 
42.         StringAssert.Contains(result, "-");
43.     }
44. 
45.     [TestMethod]
46.     public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
47.     {
48.         Assert.ThrowsExactly<ArgumentNullException>(
49.             () => _formatter.FormatPhoneNumber(null!));
50.     }
51. 
52.     [TestMethod]
53.     [DataRow("123")]
54.     [DataRow("12345678901")]
55.     [DataRow("")]
56.     public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
57.     {
58.         Assert.ThrowsExactly<ArgumentException>(
59.             () => _formatter.FormatPhoneNumber(digits));
60.     }
61. 
62.     // ── BuildGreeting ──────────────────────────────────────────────
63. 
64.     [TestMethod]
65.     public void BuildGreeting_WithDefaultTitle_ReturnsGreetingWithMr()
66.     {
67.         var result = _formatter.BuildGreeting("Smith");
68. 
69.         Assert.AreEqual("Dear Mr. Smith,", result);
70.     }
71. 
72.     [TestMethod]
73.     public void BuildGreeting_WithCustomTitle_UsesProvidedTitle()
74.     {
75.         var result = _formatter.BuildGreeting("Johnson", "Dr.");
76. 
77.         Assert.AreEqual("Dear Dr. Johnson,", result);
78.     }
79. 
80.     [TestMethod]
81.     public void BuildGreeting_Result_StartsWithDear()
82.     {
83.         var result = _formatter.BuildGreeting("Doe", "Ms.");
84. 
85.         StringAssert.StartsWith(result, "Dear ");
86.     }
87. 
88.     [TestMethod]
89.     public void BuildGreeting_Result_EndsWithComma()
90.     {
91.         var result = _formatter.BuildGreeting("Doe");
92. 
93.         StringAssert.EndsWith(result, ",");
94.     }
95. 
96.     [TestMethod]
97.     public void BuildGreeting_Result_ContainsName()
98.     {
99.         var result = _formatter.BuildGreeting("Williams", "Prof.");
100. 
101.         StringAssert.Contains(result, "Williams");
102.     }
103. 
104.     [TestMethod]
105.     public void BuildGreeting_NullName_ThrowsArgumentNullException()
106.     {
107.         Assert.ThrowsExactly<ArgumentNullException>(
108.             () => _formatter.BuildGreeting(null!));
109.     }
110. 
111.     [TestMethod]
112.     [DataRow("")]
113.     [DataRow("   ")]
114.     public void BuildGreeting_EmptyOrWhitespaceName_ThrowsArgumentException(string name)
115.     {
116.         Assert.ThrowsExactly<ArgumentException>(
117.             () => _formatter.BuildGreeting(name));
118.     }
119. 
120.     // ── GenerateSlug ───────────────────────────────────────────────
121. 
122.     [TestMethod]
123.     public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
124.     {
125.         var result = _formatter.GenerateSlug("Hello World");
126. 
127.         Assert.AreEqual("hello-world", result);
128.     }
129. 
130.     [TestMethod]
131.     public void GenerateSlug_SpecialCharacters_ReplacedWithHyphens()
132.     {
133.         var result = _formatter.GenerateSlug("C# is Great!");
134. 
135.         Assert.AreEqual("c-is-great", result);
136.     }
137. 
138.     [TestMethod]
139.     public void GenerateSlug_LeadingAndTrailingSpaces_AreTrimmed()
140.     {
141.         var result = _formatter.GenerateSlug("  My Post  ");
142. 
143.         Assert.AreEqual("my-post", result);
144.     }
145. 
146.     [TestMethod]
147.     public void GenerateSlug_ConsecutiveSpecialChars_CollapsedToSingleHyphen()
148.     {
149.         var result = _formatter.GenerateSlug("one---two");
150. 
151.         Assert.AreEqual("one-two", result);
152.     }
153. 
154.     [TestMethod]
155.     public void GenerateSlug_Result_MatchesSlugPattern()
156.     {
157.         var result = _formatter.GenerateSlug("Some Title!! Here");
158. 
